import React, { useEffect, useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { 
  LayoutDashboard, PlusCircle, List, Home, 
  CreditCard, Wallet, LogOut, User, 
  ArrowUpCircle, ArrowDownCircle, Layers
} from 'lucide-react';
import ModalFeedback from '../components/ModalFeedback';

const Sidebar = () => {
  const location = useLocation();
  const [perfil, setPerfil] = useState({ tipo: 'comum' });
  const [modalLogout, setModalLogout] = useState({ isOpen: false });

  const isActive = (path) => location.pathname === path;

  useEffect(() => {
    obterPerfil();
  }, []);

  async function obterPerfil() {
    const { data: { user } } = await supabase.auth.getUser();
    if (user) {
      const { data } = await supabase
        .from('profiles')
        .select('tipo_usuario')
        .eq('id', user.id)
        .single();
      
      const isMaster = user.email === 'gleidson.fig@gmail.com';
      if (data) setPerfil({ tipo: isMaster ? 'proprietario' : data.tipo_usuario });
    }
  }

  const handleLogout = async () => {
    await supabase.auth.signOut();
  };

  return (
    <>
      <style>{`
        .sidebar-container {
          width: 260px;
          height: 100vh;
          background: #ffffff;
          border-right: 1px solid #f1f5f9;
          padding: 30px 20px;
          position: fixed;
          left: 0;
          top: 0;
          display: flex;
          flex-direction: column;
          z-index: 1000;
          transition: all 0.3s ease;
        }

        .logo {
          display: flex;
          align-items: center;
          gap: 12px;
          font-size: 1.4rem;
          font-weight: 800;
          color: #4361ee;
          margin-bottom: 30px;
          padding-left: 10px;
        }

        .nav-list {
          display: flex;
          flex-direction: column;
          gap: 4px;
          flex: 1;
          overflow-y: auto;
          padding-right: 5px;
        }

        /* Esconder scrollbar mas manter funcionalidade */
        .nav-list::-webkit-scrollbar { width: 0; }

        .nav-item {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 12px 18px;
          text-decoration: none;
          color: #64748b;
          font-weight: 600;
          border-radius: 14px;
          transition: all 0.2s ease;
          cursor: pointer;
          border: none;
          background: none;
          width: 100%;
          text-align: left;
          font-family: inherit;
          font-size: 0.95rem;
        }

        .nav-item:hover {
          background: #f8fafc;
          color: #4361ee;
        }

        .nav-item.active {
          background: #4361ee15;
          color: #4361ee;
        }

        .logout-btn {
          margin-top: 15px;
          color: #ef4444;
          border-top: 1px solid #f1f5f9;
          padding-top: 20px;
          border-radius: 0;
        }

        .logout-btn:hover {
          background: #fef2f2;
          color: #ef4444;
          border-radius: 14px;
        }

        @media (max-width: 768px) {
          .sidebar-container {
            width: 100%;
            height: 70px;
            bottom: 0;
            top: auto;
            flex-direction: row;
            padding: 0;
            border-right: none;
            border-top: 1px solid #f1f5f9;
            justify-content: space-around;
            align-items: center;
            box-shadow: 0 -4px 15px rgba(0,0,0,0.05);
          }

          .logo { display: none; }

          .nav-list {
            flex-direction: row;
            width: 100%;
            justify-content: space-around;
            gap: 0;
            flex: none;
            overflow: visible;
          }

          .nav-item {
            flex-direction: column;
            gap: 4px;
            padding: 8px 2px;
            font-size: 0.55rem;
            border-radius: 0;
            flex: 1;
            text-align: center;
            align-items: center;
          }

          .nav-item svg {
            width: 18px;
            height: 18px;
          }

          .logout-btn { 
            margin-top: 0; 
            border-top: none; 
            padding-top: 8px;
          }
          
          /* Esconde itens menos importantes no mobile para não amontoar */
          .nav-item.desktop-only { display: none; }

          body {
            padding-bottom: 75px;
            padding-left: 0 !important;
          }
        }

        @media (min-width: 769px) {
          body { padding-left: 260px; }
        }
      `}</style>

      <aside className="sidebar-container">
        <div className="logo">
          <Wallet size={28} fill="#4361ee30" />
          <span>Finanças</span>
        </div>

        <nav className="nav-list">
          <Link to="/" className={`nav-item ${isActive('/') ? 'active' : ''}`}>
            <Home />
            <span>Início</span>
          </Link>

          {perfil.tipo === 'proprietario' && (
            <>
              <Link to="/proventos" className={`nav-item ${isActive('/proventos') ? 'active' : ''}`}>
                <ArrowUpCircle />
                <span>Entradas</span>
              </Link>
              <Link to="/despesas" className={`nav-item ${isActive('/despesas') ? 'active' : ''}`}>
                <ArrowDownCircle />
                <span>Saídas</span>
              </Link>
              <Link to="/categorias" className={`nav-item desktop-only ${isActive('/categorias') ? 'active' : ''}`}>
                <Layers />
                <span>Categorias</span>
              </Link>
            </>
          )}

          <Link to="/listagem" className={`nav-item ${isActive('/listagem') ? 'active' : ''}`}>
            <List />
            <span>Extrato</span>
          </Link>

          {perfil.tipo === 'proprietario' && (
            <Link to="/cartoes" className={`nav-item desktop-only ${isActive('/cartoes') ? 'active' : ''}`}>
              <CreditCard />
              <span>Cartões</span>
            </Link>
          )}

          <Link to="/dashboard" className={`nav-item ${isActive('/dashboard') ? 'active' : ''}`}>
            <LayoutDashboard />
            <span>Painel</span>
          </Link>

          <Link to="/perfil" className={`nav-item desktop-only ${isActive('/perfil') ? 'active' : ''}`}>
            <User />
            <span>Perfil</span>
          </Link>

          <button 
            onClick={() => setModalLogout({ isOpen: true })} 
            className="nav-item logout-btn"
          >
            <LogOut />
            <span>Sair</span>
          </button>
        </nav>
      </aside>

      <ModalFeedback
        isOpen={modalLogout.isOpen}
        type="error"
        title="Encerrar Sessão?"
        message="Você terá que entrar com suas credenciais novamente para acessar o sistema."
        onClose={() => setModalLogout({ isOpen: false })}
        onConfirm={handleLogout}
      />
    </>
  );
};

export default Sidebar;
